(function () {
  'use strict';

  function waitForThree(cb) {
    if (typeof THREE !== 'undefined') { cb(); return; }
    const s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js';
    s.onload = cb;
    document.head.appendChild(s);
  }

  // ─── HERO SPHERE ─────────────────────────────────────────────────────────
  function initHeroSphere() {
    const heroVisual = document.querySelector('.hero-visual');
    if (!heroVisual) return;

    const oldOrb = heroVisual.querySelector('.code-orb');
    if (oldOrb) oldOrb.style.display = 'none';

    const canvas = document.createElement('canvas');
    canvas.id = 'hero-three-canvas';
    canvas.style.cssText = `
      position: absolute;
      top: 0; left: 0;
      width: 100%; height: 100%;
      pointer-events: none;
      z-index: 0;
    `;
    heroVisual.style.position = 'relative';
    heroVisual.insertBefore(canvas, heroVisual.firstChild);

    const W = heroVisual.offsetWidth  || 500;
    const H = heroVisual.offsetHeight || 500;

    const renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setSize(W, H);

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(50, W / H, 0.1, 1000);
    camera.position.set(0, 0, 4);

    // Main wireframe sphere — refined opacity
    const sphereGeo = new THREE.IcosahedronGeometry(1.5, 3);
    const sphereMat = new THREE.MeshBasicMaterial({
      color: 0x00cc77,
      wireframe: true,
      transparent: true,
      opacity: 0.28,
    });
    const sphere = new THREE.Mesh(sphereGeo, sphereMat);
    scene.add(sphere);

    // Inner sphere — very subtle
    const innerGeo = new THREE.IcosahedronGeometry(0.95, 2);
    const innerMat = new THREE.MeshBasicMaterial({
      color: 0x00ffcc,
      wireframe: true,
      transparent: true,
      opacity: 0.14,
    });
    const inner = new THREE.Mesh(innerGeo, innerMat);
    scene.add(inner);

    // Orbiting dots — few, small, subtle
    const dotGroup = new THREE.Group();
    const dotGeo = new THREE.SphereGeometry(0.03, 6, 6);
    for (let i = 0; i < 30; i++) {
      const mat = new THREE.MeshBasicMaterial({
        color: i % 2 === 0 ? 0x00ee99 : 0xffffff,
        transparent: true,
        opacity: 0.55,
      });
      const dot = new THREE.Mesh(dotGeo, mat);
      const phi   = Math.acos(-1 + (2 * i) / 30);
      const theta = Math.sqrt(30 * Math.PI) * phi;
      dot.position.setFromSphericalCoords(1.75, phi, theta);
      dotGroup.add(dot);
    }
    scene.add(dotGroup);

    // Surrounding particles — sparse and subtle
    const partCount = 60;
    const partPositions = new Float32Array(partCount * 3);
    for (let i = 0; i < partCount; i++) {
      const r = 2.5 + Math.random() * 1.8;
      const phi   = Math.random() * Math.PI * 2;
      const theta = Math.random() * Math.PI;
      partPositions[i * 3]     = r * Math.sin(theta) * Math.cos(phi);
      partPositions[i * 3 + 1] = r * Math.sin(theta) * Math.sin(phi);
      partPositions[i * 3 + 2] = r * Math.cos(theta);
    }
    const partGeo = new THREE.BufferGeometry();
    partGeo.setAttribute('position', new THREE.BufferAttribute(partPositions, 3));
    const partMat = new THREE.PointsMaterial({
      color: 0x00cc88,
      size: 0.045,
      transparent: true,
      opacity: 0.5,
    });
    const particles = new THREE.Points(partGeo, partMat);
    scene.add(particles);

    let mouseX = 0, mouseY = 0;
    document.addEventListener('mousemove', (e) => {
      mouseX = (e.clientX / window.innerWidth  - 0.5) * 0.5;
      mouseY = (e.clientY / window.innerHeight - 0.5) * 0.5;
    });

    window.addEventListener('resize', () => {
      const W2 = heroVisual.offsetWidth;
      const H2 = heroVisual.offsetHeight;
      camera.aspect = W2 / H2;
      camera.updateProjectionMatrix();
      renderer.setSize(W2, H2);
    });

    let frame = 0;
    function animate() {
      requestAnimationFrame(animate);
      frame++;
      sphere.rotation.y    += 0.003;
      sphere.rotation.x    += 0.0008;
      inner.rotation.y     -= 0.004;
      inner.rotation.z     += 0.002;
      dotGroup.rotation.y  += 0.004;
      dotGroup.rotation.x  += 0.0015;
      particles.rotation.y += 0.0007;

      camera.position.x += (mouseX - camera.position.x) * 0.03;
      camera.position.y += (-mouseY - camera.position.y) * 0.03;
      camera.lookAt(scene.position);

      // Gentle pulse — very subtle range
      const pulse = 0.22 + 0.06 * Math.sin(frame * 0.025);
      sphereMat.opacity = pulse;

      renderer.render(scene, camera);
    }
    animate();
  }

  // ─── BACKGROUND PARTICLES (dark sections) ────────────────────────────────
  function initBgParticles() {
    const targets = document.querySelectorAll(
      '.hero, .pricing-section, .partners-section, .team-showcase, .process-section, .page-header'
    );
    if (!targets.length) return;

    targets.forEach((section) => {
      if (section.querySelector('.bg-three-canvas')) return;

      const canvas = document.createElement('canvas');
      canvas.className = 'bg-three-canvas';
      canvas.style.cssText = `
        position: absolute;
        top: 0; left: 0;
        width: 100%; height: 100%;
        pointer-events: none;
        z-index: 0;
        opacity: 1;
      `;
      const pos = getComputedStyle(section).position;
      if (pos === 'static') section.style.position = 'relative';
      section.insertBefore(canvas, section.firstChild);

      const W = section.offsetWidth  || window.innerWidth;
      const H = section.offsetHeight || 400;

      const renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: false });
      renderer.setPixelRatio(1);
      renderer.setSize(W, H);

      const scene = new THREE.Scene();
      const camera = new THREE.PerspectiveCamera(60, W / H, 0.1, 100);
      camera.position.z = 5;

      // Fewer particles, much more subtle
      const count = window.innerWidth < 768 ? 50 : 90;
      const positions  = new Float32Array(count * 3);
      const velocities = new Float32Array(count * 3);
      for (let i = 0; i < count; i++) {
        positions[i * 3]     = (Math.random() - 0.5) * 16;
        positions[i * 3 + 1] = (Math.random() - 0.5) * 10;
        positions[i * 3 + 2] = (Math.random() - 0.5) * 4;
        velocities[i * 3]     = (Math.random() - 0.5) * 0.004;
        velocities[i * 3 + 1] = (Math.random() - 0.5) * 0.004;
      }

      const geo     = new THREE.BufferGeometry();
      const posAttr = new THREE.BufferAttribute(positions, 3);
      geo.setAttribute('position', posAttr);

      const mat = new THREE.PointsMaterial({
        color: 0x00bb77,
        size: 0.055,        // small
        transparent: true,
        opacity: 0.38,      // noticeably subtle
      });
      const pts = new THREE.Points(geo, mat);
      scene.add(pts);

      // Lines — very thin and barely-there
      const lineMat = new THREE.LineBasicMaterial({
        color: 0x00cc77,
        transparent: true,
        opacity: 0.10,      // extremely faint — texture, not noise
      });

      let lineObj  = null;
      let lineTimer = 0;

      function buildLines() {
        const lp = [];
        const maxDist = 2.2;   // tighter connection radius = fewer lines
        for (let i = 0; i < count; i++) {
          let connections = 0;
          for (let j = i + 1; j < count; j++) {
            if (connections >= 2) break;  // each node connects to max 2 others
            const dx = positions[i*3]   - positions[j*3];
            const dy = positions[i*3+1] - positions[j*3+1];
            const dz = positions[i*3+2] - positions[j*3+2];
            if (Math.sqrt(dx*dx + dy*dy + dz*dz) < maxDist) {
              lp.push(
                positions[i*3], positions[i*3+1], positions[i*3+2],
                positions[j*3], positions[j*3+1], positions[j*3+2]
              );
              connections++;
            }
          }
        }
        return lp;
      }

      function updateLines() {
        if (lineObj) scene.remove(lineObj);
        const lp = buildLines();
        if (!lp.length) return;
        const lgeo = new THREE.BufferGeometry();
        lgeo.setAttribute('position', new THREE.BufferAttribute(new Float32Array(lp), 3));
        lineObj = new THREE.LineSegments(lgeo, lineMat);
        scene.add(lineObj);
      }
      updateLines();

      const ro = new ResizeObserver(() => {
        const w = section.offsetWidth;
        const h = section.offsetHeight;
        camera.aspect = w / h;
        camera.updateProjectionMatrix();
        renderer.setSize(w, h);
      });
      ro.observe(section);

      let tick = 0;
      function animate() {
        requestAnimationFrame(animate);
        tick++;
        for (let i = 0; i < count; i++) {
          positions[i*3]   += velocities[i*3];
          positions[i*3+1] += velocities[i*3+1];
          if (positions[i*3]   >  8)  positions[i*3]   = -8;
          if (positions[i*3]   < -8)  positions[i*3]   =  8;
          if (positions[i*3+1] >  5)  positions[i*3+1] = -5;
          if (positions[i*3+1] < -5)  positions[i*3+1] =  5;
        }
        posAttr.needsUpdate = true;
        // Rebuild lines far less often — every 90 frames (~1.5s at 60fps)
        if (tick % 90 === 0) updateLines();
        renderer.render(scene, camera);
      }
      animate();
    });
  }

  // ─── 3D CARD TILT ────────────────────────────────────────────────────────
  function initCardTilt() {
    const cards = document.querySelectorAll(
      '.service-card, .partner-card, .portfolio-card, .value-card, .step, .team-card, .pricing-card, .service-detailed-card'
    );
    cards.forEach((card) => {
      card.addEventListener('mousemove', (e) => {
        const rect = card.getBoundingClientRect();
        const rotX = ((e.clientY - rect.top  - rect.height / 2) / rect.height) * -10;
        const rotY = ((e.clientX - rect.left - rect.width  / 2) / rect.width)  *  10;
        card.style.transition = 'transform 0.1s ease';
        card.style.transform  = `perspective(800px) rotateX(${rotX}deg) rotateY(${rotY}deg) translateY(-5px) scale(1.02)`;
      });
      card.addEventListener('mouseleave', () => {
        card.style.transition = 'transform 0.5s cubic-bezier(0.23,1,0.32,1)';
        card.style.transform  = 'perspective(800px) rotateX(0deg) rotateY(0deg) translateY(0) scale(1)';
      });
    });
  }

  // ─── FLOATING CARD TILT ──────────────────────────────────────────────────
  function initFloatingCardTilt() {
    document.querySelectorAll('.floating-card').forEach((card) => {
      card.addEventListener('mousemove', (e) => {
        const rect = card.getBoundingClientRect();
        const x = ((e.clientX - rect.left) / rect.width  - 0.5) * 18;
        const y = ((e.clientY - rect.top)  / rect.height - 0.5) * 18;
        card.style.transform = `perspective(500px) rotateX(${-y}deg) rotateY(${x}deg) scale(1.08)`;
      });
      card.addEventListener('mouseleave', () => {
        card.style.transform = '';
      });
    });
  }

  // ─── BOOT ────────────────────────────────────────────────────────────────
  function boot() {
    waitForThree(() => {
      initHeroSphere();
      initBgParticles();
      initCardTilt();
      initFloatingCardTilt();
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    boot();
  }
})();